import argparse
import json
import random
import signal
import socket
import sys
import threading
import time
from typing import Dict, List, Tuple


class GameState:
    def __init__(self) -> None:
        self.lock = threading.Lock()
        self.server_name = "Example Game Server"
        self.map_name = "arena_01"
        self.mode = "deathmatch"
        self.max_players = 64
        self.tick = 0
        self.round = 1
        self.time_remaining = 900
        self.players = self._generate_players(48)

    def _generate_players(self, count: int) -> List[Dict]:
        players = []
        for i in range(count):
            players.append(
                {
                    "id": i + 1,
                    "name": f"Player_{i+1}",
                    "score": random.randint(0, 100),
                    "ping": random.randint(20, 120),
                    "team": random.choice(["red", "blue", "spectator"]),
                    "alive": random.choice([True, False]),
                }
            )
        return players

    def update(self) -> None:
        with self.lock:
            self.tick += 1
            if self.tick % 10 == 0:
                self.time_remaining = max(0, self.time_remaining - 1)
            if self.tick % 300 == 0:
                self.round += 1
            for p in self.players:
                if random.random() < 0.15:
                    p["score"] += random.randint(0, 3)
                if random.random() < 0.10:
                    p["ping"] = max(5, min(250, p["ping"] + random.randint(-10, 10)))
                if random.random() < 0.05:
                    p["alive"] = not p["alive"]

    def status_payload(self) -> bytes:
        with self.lock:
            payload = {
                "type": "status",
                "server": {
                    "name": self.server_name,
                    "map": self.map_name,
                    "mode": self.mode,
                    "players": len(self.players),
                    "max_players": self.max_players,
                    "tick": self.tick,
                    "round": self.round,
                    "time_remaining": self.time_remaining,
                },
                "players": list(self.players),
            }
        return json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")


class UDPGameServer:
    def __init__(self, host: str, port: int, state: GameState) -> None:
        self.host = host
        self.port = port
        self.state = state
        self.running = False
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)

    def serve_forever(self) -> None:
        self.running = True
        while self.running:
            try:
                data, addr = self.sock.recvfrom(65535)
            except socket.timeout:
                continue
            except OSError:
                break
            if not data:
                continue
            self.handle_packet(data, addr)

    def handle_packet(self, data: bytes, addr: Tuple[str, int]) -> None:
        msg = data.strip().decode("utf-8", errors="ignore").lower()
        if msg in ("status", "getstatus", "query_status", "serverinfo"):
            response = self.state.status_payload()
            self.sock.sendto(response, addr)
        else:
            response = json.dumps(
                {"type": "error", "message": "unknown_query"}
            ).encode("utf-8")
            self.sock.sendto(response, addr)

    def shutdown(self) -> None:
        self.running = False
        try:
            self.sock.close()
        except OSError:
            pass


def state_updater(state: GameState, stop_event: threading.Event) -> None:
    while not stop_event.is_set():
        state.update()
        time.sleep(0.1)


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=27015)
    args = parser.parse_args()

    state = GameState()
    server = UDPGameServer(args.host, args.port, state)
    stop_event = threading.Event()

    updater_thread = threading.Thread(target=state_updater, args=(state, stop_event), daemon=True)
    updater_thread.start()

    def handle_shutdown(signum, frame):
        stop_event.set()
        server.shutdown()

    signal.signal(signal.SIGINT, handle_shutdown)
    signal.signal(signal.SIGTERM, handle_shutdown)

    try:
        server.serve_forever()
    finally:
        stop_event.set()
        server.shutdown()

    return 0


if __name__ == "__main__":
    sys.exit(main())